// TAXONOMY v1.0 — Controlled Vocabularies
const UNIVERSES    = ['hwc', 'home', 'sys'];
const DOMAINS      = ['ops', 'financial', 'dev', 'admin', 'security', 'media', 'social'];
const CATEGORIES   = ['lead', 'client-comms', 'job-update', 'payment', 'receipt', 'workflow', 'infrastructure', 'content', 'detection', 'backup', 'digest', 'reminder'];
const SEVERITIES   = ['critical', 'warning', 'info', 'debug'];
const ACTION_HINTS = ['restart-service', 'retry-workflow', 'escalate', 'classify', 'sync', 'draft-response', 'none'];

const p = $input.first().json;

// ── Validate required fields ──────────────────────────────────────────────────
const required = ['universe', 'domain', 'source', 'category', 'severity', 'summary', 'timestamp'];
for (const field of required) {
  if (!p[field]) throw new Error(`sys:router:notify — missing required field: ${field}`);
}

// ── Validate controlled vocabularies ─────────────────────────────────────────
if (!UNIVERSES.includes(p.universe))   throw new Error(`Invalid universe: "${p.universe}". Valid: ${UNIVERSES.join(', ')}`);
if (!DOMAINS.includes(p.domain))       throw new Error(`Invalid domain: "${p.domain}". Valid: ${DOMAINS.join(', ')}`);
if (!CATEGORIES.includes(p.category)) throw new Error(`Invalid category: "${p.category}". Valid: ${CATEGORIES.join(', ')}`);
if (!SEVERITIES.includes(p.severity)) throw new Error(`Invalid severity: "${p.severity}". Valid: ${SEVERITIES.join(', ')}`);

const actionHint = p.action_hint || 'none';
if (!ACTION_HINTS.includes(actionHint)) throw new Error(`Invalid action_hint: "${actionHint}". Valid: ${ACTION_HINTS.join(', ')}`);

// ── Severity → Gotify priority ────────────────────────────────────────────────
const priorityMap = { critical: 8, warning: 5, info: 3, debug: 1 };

// ── Gotify token env var per universe:domain ─────────────────────────────────
// Tokens set in n8n Settings → Environment Variables:
//   GOTIFY_TOKEN_HWC_OPS, GOTIFY_TOKEN_HWC_FINANCIAL, GOTIFY_TOKEN_HWC_DEV,
//   GOTIFY_TOKEN_HWC_ADMIN, GOTIFY_TOKEN_HOME_SECURITY, GOTIFY_TOKEN_HOME_MEDIA,
//   GOTIFY_TOKEN_HOME_SOCIAL, GOTIFY_TOKEN_HOME_ADMIN
const tokenEnvMap = {
  'hwc:ops':       'GOTIFY_TOKEN_HWC_OPS',
  'hwc:financial': 'GOTIFY_TOKEN_HWC_FINANCIAL',
  'hwc:dev':       'GOTIFY_TOKEN_HWC_DEV',
  'hwc:admin':     'GOTIFY_TOKEN_HWC_ADMIN',
  'home:security': 'GOTIFY_TOKEN_HOME_SECURITY',
  'home:media':    'GOTIFY_TOKEN_HOME_MEDIA',
  'home:social':   'GOTIFY_TOKEN_HOME_SOCIAL',
  'home:admin':    'GOTIFY_TOKEN_HOME_ADMIN',
};

const appKey      = `${p.universe}:${p.domain}`;
const tokenEnv    = tokenEnvMap[appKey];
const gotifyToken = tokenEnv ? ($env[tokenEnv] || '') : '';

// ── Slack message ─────────────────────────────────────────────────────────────
const emoji = { critical: '🔴', warning: '🟡', info: '🟢', debug: '⚪' };

const meta = p.metadata && Object.keys(p.metadata).length > 0
  ? '\n```\n' + JSON.stringify(p.metadata, null, 2) + '\n```'
  : '';

const slackText = [
  `${emoji[p.severity] || '⚪'} *${p.summary}*`,
  `\`${appKey}:${p.source}:${p.category}\` | ${p.severity}${ actionHint !== 'none' ? ` | hint: ${actionHint}` : '' }`,
  `_${p.timestamp}_${meta}`
].join('\n');

return [{
  json: {
    // Validated payload
    universe:    p.universe,
    domain:      p.domain,
    source:      p.source,
    category:    p.category,
    severity:    p.severity,
    summary:     p.summary,
    action_hint: actionHint,
    timestamp:   p.timestamp,
    metadata:    p.metadata || {},
    // Routing
    slack_channel:   `${p.universe}-${p.domain}`,
    gotify_app:      appKey,
    gotify_token:    gotifyToken,
    gotify_priority: priorityMap[p.severity] || 3,
    gotify_title:    `${p.source}: ${p.category}`,
    slack_text:      slackText,
  }
}];

